				let py : f32 = ndc.y / uniform.fisheye_projMat11;
				let r : f32 = sqrt(px * px + py * py);
				let theta : f32 = uniform.fisheye_k * atan(r * uniform.fisheye_invK);
				let sinT : f32 = sin(theta);
				let cosT : f32 = cos(theta);
